#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct { double t; int a; int b; } Event;
int cmpEvent(const void *x, const void *y) {
    double diff = ((Event*)x)->t - ((Event*)y)->t;
    if (diff < 0) return -1;
    if (diff > 0) return 1;
    return 0;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int V[5];
        for(int i=0;i<N;i++) scanf("%d", &V[i]);
        Event ev[10]; int ec=0;
        for(int i=0;i<N;i++){
            for(int j=i+1;j<N;j++){
                if(V[i]>V[j]){
                    ev[ec].t = (double)(j-i)/(V[i]-V[j]);
                    ev[ec].a = i; ev[ec].b = j; ec++;
                }
            }
        }
        qsort(ev, ec, sizeof(Event), cmpEvent);
        int best=N, worst=1;
        for(int start=0; start<N; ++start){
            bool inf[5]={0}; inf[start]=true;
            for(int e=0;e<ec;e++){
                int a=ev[e].a, b=ev[e].b;
                if(inf[a] && !inf[b]) inf[b]=true;
                else if(inf[b] && !inf[a]) inf[a]=true;
            }
            int cnt=0; for(int i=0;i<N;i++) if(inf[i]) cnt++;
            if(cnt<best) best=cnt;
            if(cnt>worst) worst=cnt;
        }
        printf("%d %d\n", best, worst);
    }
    return 0;
}

