import java.io.*;
import java.util.*;
public class Main {
    static class Event {
        double t; int a,b;
        Event(double t,int a,int b){this.t=t;this.a=a;this.b=b;}
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] V = new int[N];
            for (int i = 0; i < N; i++) V[i] = fs.nextInt();
            List<Event> list = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (V[i] > V[j]) {
                        double t = (double)(j - i) / (V[i] - V[j]);
                        list.add(new Event(t, i, j));
                    }
                }
            }
            list.sort(Comparator.comparingDouble(e -> e.t));
            int best = N, worst = 1;
            for (int start = 0; start < N; start++) {
                boolean[] inf = new boolean[N];
                inf[start] = true;
                for (Event e : list) {
                    if (inf[e.a] && !inf[e.b]) inf[e.b] = true;
                    else if (inf[e.b] && !inf[e.a]) inf[e.a] = true;
                }
                int cnt = 0; for (boolean b : inf) if (b) cnt++;
                best = Math.min(best, cnt);
                worst = Math.max(worst, cnt);
            }
            sb.append(best).append(' ').append(worst).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for competitive programming
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

