#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        V = [int(next(it)) for _ in range(N)]
        events = []
        for i in range(N):
            for j in range(i+1, N):
                if V[i] > V[j]:
                    t = (j - i) / (V[i] - V[j])
                    events.append((t, i, j))
        events.sort(key=lambda x: x[0])
        best, worst = N, 1
        for start in range(N):
            infected = [False]*N
            infected[start] = True
            for _, a, b in events:
                if infected[a] and not infected[b]:
                    infected[b] = True
                elif infected[b] and not infected[a]:
                    infected[a] = True
            cnt = sum(infected)
            best = min(best, cnt)
            worst = max(worst, cnt)
        out_lines.append(f"{best} {worst}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

