const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  const V = [];
  for (let i = 0; i < N; ++i) V.push(input[idx++]);
  const events = [];
  for (let i = 0; i < N; ++i) {
    for (let j = i + 1; j < N; ++j) {
      if (V[i] > V[j]) {
        const t = (j - i) / (V[i] - V[j]);
        events.push({t, a: i, b: j});
      }
    }
  }
  events.sort((e1, e2) => e1.t - e2.t);
  let best = N, worst = 1;
  for (let start = 0; start < N; ++start) {
    const inf = new Array(N).fill(false);
    inf[start] = true;
    for (const e of events) {
      if (inf[e.a] && !inf[e.b]) inf[e.b] = true;
      else if (inf[e.b] && !inf[e.a]) inf[e.a] = true;
    }
    const cnt = inf.reduce((s, v) => s + (v ? 1 : 0), 0);
    if (cnt < best) best = cnt;
    if (cnt > worst) worst = cnt;
  }
  out.push(best + ' ' + worst);
}
